    static func randomMessage() -> NotificationMessage {
        all.randomElement() ?? all[0]
    }

    static func randomMessage(from category: NotificationCategory) -> NotificationMessage {
        let filtered = all.filter { $0.category == category }
        return filtered.randomElement() ?? all[0]
    }

    static func randomMessages(count: Int, excluding usedIndices: Set<Int>) -> [(Int, NotificationMessage)] {
        var available = Array(all.enumerated()).filter { !usedIndices.contains($0.offset) }
        if available.count < count {
            available = Array(all.enumerated())
        }
        available.shuffle()
        return Array(available.prefix(count)).map { ($0.offset, $0.element) }
    }
